    pq.enqueue({ cost: 0, i: 0, j: 0, trans: 0 });

    while (!pq.isEmpty()) {
        const { cost, i, j, trans } = pq.dequeue();
        if (i === m - 1 && j === n - 1) return cost;
        if (trans >= k) {
            // No more teleportations allowed
            for (const [di, dj] of dirs) {
                const ni = i + di;
                const nj = j + dj;
                if (ni < m && nj < n) {
                    const newCost = cost + grid[ni][nj];
                    if (newCost < dist[ni][nj]) {
                        dist[ni][nj] = newCost;
                        pq.enqueue({ cost: newCost, i: ni, j: nj, trans: trans });
                    }
                }
            }
            continue;
        }

        // Regular move (right or down)
        for (const [di, dj] of dirs) {
            const ni = i + di;
            const nj = j + dj;
            if (ni < m && nj < n) {
                const newCost = cost + grid[ni][nj];
                if (newCost < dist[ni][nj]) {
                    dist[ni][nj] = newCost;
                    pq.enqueue({ cost: newCost, i: ni, j: nj, trans: trans });
                }
            }
        }

        // Teleportation
        for (let x = 0; x < m; x++) {
            for (let y = 0; y < n; y++) {
                if (grid[x][y] <= grid[i][j] && x !== i || y !== j) {
                    if (dist[x][y] > cost) {
                        dist[x][y] = cost;
                        pq.enqueue({ cost: cost, i: x, j: y, trans: trans + 1 });
                    }
                }
            }
        }
    }

    return dist[m - 1][n - 1];
}

