    constructor(comparator) {
        this.comparator = comparator;
        this.heap = [];
    }

    enqueue(item) {
        this.heap.push(item);
        this.heap.sort(this.comparator);
    }

    dequeue() {
        return this.heap.shift();
    }

    isEmpty() {
        return this.heap.length === 0;
