import heapq

def solve(grid: list[list[int]], k: int) -> int:
    m, n = len(grid), len(grid[0])
    dist = [[float('inf')] * n for _ in range(m)]
    dist[0][0] = 0

    dirs = [(0, 1), (1, 0)]  # right, down

    # Priority queue: (cost, i, j, trans)
    pq = [(0, 0, 0, 0)]

    while pq:
        cost, i, j, trans = heapq.heappop(pq)
        if i == m - 1 and j == n - 1:
            return cost
        if trans >= k:
            # No more teleportations allowed
            for di, dj in dirs:
                ni, nj = i + di, j + dj
                if 0 <= ni < m and 0 <= nj < n:
                    new_cost = cost + grid[ni][nj]
                    if new_cost < dist[ni][nj]:
                        dist[ni][nj] = new_cost
                        heapq.heappush(pq, (new_cost, ni, nj, trans))
            continue

        # Regular move (right or down)
        for di, dj in dirs:
            ni, nj = i + di, j + dj
            if 0 <= ni < m and 0 <= nj < n:
                new_cost = cost + grid[ni][nj]
                if new_cost < dist[ni][nj]:
                    dist[ni][nj] = new_cost
                    heapq.heappush(pq, (new_cost, ni, nj, trans))

